import java.util.NoSuchElementException;
import static org.apache.commons.csv.Token.Type.*;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a dummy CSVFormat instance (can be null if not used in isClosed)
        CSVFormat format = mock(CSVFormat.class);

        // Create the parser normally
        parser = new CSVParser(new java.io.StringReader(""), format);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Use reflection to set the private final lexer field to the mock
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);

        // Directly set the field without removing final modifier (works in modern JVMs)
        lexerField.set(parser, lexerMock);
    }

    @Test
    public void testIsClosed_whenLexerIsClosed_returnsTrue() {
        when(lexerMock.isClosed()).thenReturn(true);
        assertTrue(parser.isClosed());
        verify(lexerMock).isClosed();
    }

    @Test
    public void testIsClosed_whenLexerIsNotClosed_returnsFalse() {
        when(lexerMock.isClosed()).thenReturn(false);
        assertFalse(parser.isClosed());
        verify(lexerMock).isClosed();
    }
}
